-- Test 2
SELECT 'DIM_Company' as table_name, COUNT(*) FROM "DIM_Company"
UNION ALL SELECT 'DIM_Job_Title', COUNT(*) FROM "DIM_Job_Title"
UNION ALL SELECT 'DIM_Skill', COUNT(*) FROM "DIM_Skill"
UNION ALL SELECT 'DIM_Location', COUNT(*) FROM "DIM_Location"
UNION ALL SELECT 'DIM_Industry', COUNT(*) FROM "DIM_Industry"
UNION ALL SELECT 'DIM_Experience_Level', COUNT(*) FROM "DIM_Experience_Level"
UNION ALL SELECT 'DIM_Date_Posted', COUNT(*) FROM "DIM_Date_Posted"
UNION ALL SELECT 'FACT_Job_Posting', COUNT(*) FROM "FACT_Job_Posting"
UNION ALL SELECT 'FACT_Job_Skill', COUNT(*) FROM "FACT_Job_Skill"
UNION ALL SELECT 'FACT_Job_Location', COUNT(*) FROM "FACT_Job_Location"
UNION ALL SELECT 'FACT_Company_Industry', COUNT(*) FROM "FACT_Company_Industry";

-- Test 3
SELECT 
    f.job_posting_id,
    c.company_name,
    t.job_title,
    e.experience_level,
    f.salary_min,
    f.salary_max,
    l.city,
    f.date_posted
FROM "FACT_Job_Posting" f
JOIN "DIM_Company" c ON f.company_id = c.company_id
JOIN "DIM_Job_Title" t ON f.job_title_id = t.job_title_id
JOIN "DIM_Experience_Level" e ON f.experience_level_id = e.experience_level_id
JOIN "FACT_Job_Location" fl ON f.job_posting_id = fl.job_posting_id
JOIN "DIM_Location" l ON fl.location_id = l.location_id
LIMIT 10;


-- Test 4
SELECT 
    s.skill_name,
    s.skill_category,
    s.skill_type,
    COUNT(*) as demand_count
FROM "FACT_Job_Skill" fs
JOIN "DIM_Skill" s ON fs.skill_id = s.skill_id
GROUP BY s.skill_name, s.skill_category, s.skill_type
ORDER BY demand_count DESC
LIMIT 10;

-- Test 5
SELECT 
    e.experience_level,
    ROUND(AVG(f.salary_min)) as avg_salary_min,
    ROUND(AVG(f.salary_max)) as avg_salary_max
FROM "FACT_Job_Posting" f
JOIN "DIM_Experience_Level" e ON f.experience_level_id = e.experience_level_id
GROUP BY e.experience_level
ORDER BY avg_salary_min;

-- Test 6
SELECT 
    f.job_posting_id,
    t.job_title,
    s.skill_name
FROM "FACT_Job_Skill" fs
JOIN "FACT_Job_Posting" f ON fs.job_posting_id = f.job_posting_id
JOIN "DIM_Job_Title" t ON f.job_title_id = t.job_title_id
JOIN "DIM_Skill" s ON fs.skill_id = s.skill_id
LIMIT 15;


select * from "FACT_Job_Posting" fjp 

-- 83 Companies 
select * from "DIM_Company" dc 

-- Entire Dataset
SELECT 
    f.job_posting_id,
    c.company_name,
    t.job_title
FROM "FACT_Job_Posting" f
JOIN "DIM_Company" c ON f.company_id = c.company_id
JOIN "DIM_Job_Title" t ON f.job_title_id = t.job_title_id
ORDER BY f.job_posting_id;

-- Test for Duplicate Companies
SELECT 
    c.company_name,
    COUNT(*) as jobs_posted
FROM "FACT_Job_Posting" f
JOIN "DIM_Company" c ON f.company_id = c.company_id
GROUP BY c.company_name
HAVING COUNT(*) > 1
ORDER BY jobs_posted DESC;

-- Data Insights' Number of Postings
SELECT f.job_posting_id, c.company_name 
FROM "FACT_Job_Posting" f
JOIN "DIM_Company" c ON f.company_id = c.company_id
WHERE c.company_name = 'Data Insights';

-- Most Active Recruiters
SELECT 
    c.company_name,
    COUNT(*) as jobs_posted
FROM "FACT_Job_Posting" f
JOIN "DIM_Company" c ON f.company_id = c.company_id
GROUP BY c.company_name
ORDER BY jobs_posted DESC;